const passActive = "passActive";
let initialState = {
   password:{
      type:"text",
      classN:"name"
   }
}
export const passwordReducer = (state = initialState, action) =>{
   let stateCopy = {...state};
   stateCopy.password = {...state.password}
   if(action.type === passActive){
      if(state.password.type === "password"){
         stateCopy.password.type = "text";
         stateCopy.password.classN = "active";
      }
      if(state.password.type === "text"){
         state.password.type = "password";
         state.password.classN = "none";
      }
   }
   console.log(state);
   return state;
}
